// Some portions generated by Codex
package org.eclipse.rdf4j.query.resultio.binary;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.util.List;

import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.RDF;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.impl.MapBindingSet;
import org.eclipse.rdf4j.query.resultio.helpers.QueryResultCollector;
import org.junit.jupiter.api.Test;

public class BinaryQueryResultDirectedLanguageLiteralTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	public void roundTripPreservesDirectedLanguageLiteralBaseDirection() throws Exception {
		Literal literal = VF.createLiteral("שלום", "he", Literal.BaseDirection.RTL);
		ByteArrayOutputStream output = new ByteArrayOutputStream();
		BinaryQueryResultWriter writer = new BinaryQueryResultWriter(output);
		MapBindingSet bindingSet = new MapBindingSet();
		bindingSet.addBinding("value", literal);

		writer.startQueryResult(List.of("value"));
		writer.handleSolution(bindingSet);
		writer.endQueryResult();

		QueryResultCollector collector = new QueryResultCollector();
		BinaryQueryResultParser parser = new BinaryQueryResultParser();
		parser.setQueryResultHandler(collector);
		parser.parseQueryResult(new ByteArrayInputStream(output.toByteArray()));

		BindingSet parsed = collector.getBindingSets().get(0);
		Literal parsedLiteral = (Literal) parsed.getValue("value");
		assertEquals("he", parsedLiteral.getLanguage().orElse(null));
		assertEquals(Literal.BaseDirection.RTL, parsedLiteral.getBaseDirection());
		assertEquals(RDF.DIRLANGSTRING, parsedLiteral.getDatatype());
	}
}
